from string_utils.manipulation import compress
from mutant.string_utils.manipulation import compress as mutant_compress

def test_empty_string_correct_code():
    try:
        compress("")  # Should raise a ValueError
        print("correct code did not raise an error.")
    except ValueError:
        print("correct code raised ValueError as expected.")

def test_empty_string_mutant_code():
    try:
        mutant_compress("")  # Should NOT raise an error
        print("mutant code did not raise an error.")
    except ValueError:
        print("mutant code raised ValueError, which is unexpected.")

test_empty_string_correct_code()
test_empty_string_mutant_code()

